import React from 'react';
import { useParams, Link } from 'react-router-dom';

function PostPage({ posts }) {
  const { id } = useParams();
  const post = posts[parseInt(id)];

  if (!post) {
    return (
      <div style={{ padding: '2rem' }}>
        <h2>Post not found</h2>
        <Link to="/">← Back to blog</Link>
      </div>
    );
  }

  return (
    <div style={{ padding: '2rem' }}>
      <Link to="/" style={{ textDecoration: 'none', color: 'blue' }}>← Back to blog</Link>
      <h1 style={{ marginTop: '1rem' }}>{post.title}</h1>
      {post.date && (
        <p style={{ fontStyle: 'italic', color: 'gray', marginTop: '-0.5rem' }}>
          Posted on {post.date}
        </p>
      )}
      <div
        dangerouslySetInnerHTML={{ __html: post.content }}
        style={{ marginTop: '2rem', lineHeight: '1.6' }}
      />
    </div>
  );
}

export default PostPage;
